from dataclasses import dataclass
from datetime import datetime, timedelta, timezone
from typing import Optional


# SLA definitions in business days from report submission
SLA_CONFIG = {
    "critical": {
        "ack_hours": 24,
        "verdict_hours": 48,
        "fix_days": 7,
        "max_extension_days": 14,
        "post_fix_disclosure_days": 14,
    },
    "high": {
        "ack_hours": 48,
        "verdict_hours": 120,   # 5 business days
        "fix_days": 30,
        "max_extension_days": 14,
        "post_fix_disclosure_days": 30,
    },
    "medium": {
        "ack_hours": 120,       # 5 business days
        "verdict_hours": 240,   # 10 business days
        "fix_days": 90,
        "max_extension_days": 30,
        "post_fix_disclosure_days": 30,
    },
    "low": {
        "ack_hours": 240,
        "verdict_hours": 360,   # 15 business days
        "fix_days": 180,
        "max_extension_days": 30,
        "post_fix_disclosure_days": 30,
    },
}


@dataclass
class SLATimeline:
    case_id: str
    severity: str
    submitted_at: datetime
    ack_due: datetime
    verdict_due: datetime
    fix_due: datetime
    post_fix_disclosure_window_days: int
    extension_granted: Optional[datetime] = None

    @property
    def fix_deadline(self) -> datetime:
        return self.extension_granted or self.fix_due

    def earliest_researcher_disclosure(self, fix_deployed_at: datetime) -> datetime:
        """Earliest date the researcher may disclose after the fix is deployed."""
        config = SLA_CONFIG[self.severity]
        return fix_deployed_at + timedelta(days=config["post_fix_disclosure_days"])

    def researcher_can_disclose_now(self, fix_deployed_at: Optional[datetime]) -> bool:
        """Can the researcher publish today?"""
        now = datetime.now(timezone.utc)
        if fix_deployed_at is None:
            # Fix not deployed — researcher may disclose 7 days after deadline miss
            return now > self.fix_deadline + timedelta(days=7)
        return now >= self.earliest_researcher_disclosure(fix_deployed_at)


def create_sla_timeline(case_id: str, severity: str, submitted_at: datetime) -> SLATimeline:
    config = SLA_CONFIG[severity]
    return SLATimeline(
        case_id=case_id,
        severity=severity,
        submitted_at=submitted_at,
        ack_due=submitted_at + timedelta(hours=config["ack_hours"]),
        verdict_due=submitted_at + timedelta(hours=config["verdict_hours"]),
        fix_due=submitted_at + timedelta(days=config["fix_days"]),
        post_fix_disclosure_window_days=config["post_fix_disclosure_days"],
    )


# Example: Critical vulnerability submitted now
timeline = create_sla_timeline(
    case_id="VDP-2024-0143",
    severity="critical",
    submitted_at=datetime.now(timezone.utc),
)
print(f"ACK due: {timeline.ack_due}")
print(f"Verdict due: {timeline.verdict_due}")
print(f"Fix due: {timeline.fix_due}")
